const j = $input.first().json || {};
const t = String(j.type || '').toLowerCase();
const echoBase = { number: j.number, type: j.type, text: j.text, items: null, trackSource: j.trackSource, trackId: j.trackId, options: {} };
if (!['button','list','poll'].includes(t)) {
  return [{ json: { _err: 'bad_type', echo: Object.assign({}, echoBase, { items: null }) } }];
}
let items = [];
try { items = JSON.parse(j.itemsJson || '[]'); } catch (e) {
  return [{ json: { _err: 'bad_itemsJson', echo: Object.assign({}, echoBase, { items: null }) } }];
}
let opt = {};
try { opt = JSON.parse(j.optionsJson || '{}'); } catch (e) { opt = {}; }
const num = String(j.number || '').replace(/\D/g, '');
if (!num) {
  return [{ json: { _err: 'bad_number', echo: Object.assign({}, echoBase, { items: items, options: opt }) } }];
}
const baseUrl = String(j.baseUrl || 'https://rnbsolucoes.uazapi.com').replace(/\/$/, '');
const body = { number: num, type: t, text: String(j.text || ''), delay: opt.delay != null ? Number(opt.delay) : 500, track_source: String(j.trackSource || 'barbearia.amy'), track_id: String(j.trackId || 'turn') };
if (t === 'button') {
  body.choices = (items || []).map(function(it) { if (typeof it === 'string') return it; return (it.label || '') + '|' + (it.id || it.label || ''); });
} else if (t === 'list') {
  body.listButton = opt.listButton || 'Ver opções';
  body.footerText = opt.footerText || '';
  body.choices = (items || []).map(function(it) { return typeof it === 'string' ? it : (it.label || it.id || String(it)); });
} else {
  body.selectableCount = opt.selectableCount != null ? Number(opt.selectableCount) : 1;
  body.choices = (items || []).map(function(it) { return typeof it === 'string' ? it : (it.label || it.id); });
}
const echo = { number: j.number, type: t, text: j.text, items: items, trackSource: j.trackSource, trackId: j.trackId, options: opt };
return [{ json: { baseUrl: baseUrl, body: body, echo: echo } }];

const r = $input.first().json;
const b = $('FN_BuildUazapiMenuPayload').first().json;
const err = r.error;
const mid = r.messageid || r.messageId || (r.body && r.body.id) || null;
const sc = r.statusCode || 0;
const ok = !err && (sc === 200 || sc === 201 || !!mid);
return [{ json: {
  ok: ok,
  messageId: mid,
  sentAt: new Date().toISOString(),
  echo: b.echo,
  error: err ? JSON.stringify(err) : (ok ? undefined : ('http:' + sc + ' ' + JSON.stringify(r).slice(0, 400)))
} }];

